function Get-MaxValue {
    param([int32]$Value1, [int32]$Value2)
    return [Math]::Max($Value1, $Value2)
}

function Get-Drive-Failure-Event {
    param($Disk, $ScsiId, $drvErrLog)
    foreach ($drvEvent in $drvErrLog) {
        if ($drvEvent.Line -match 'CH(?:L)?[:\s]+(?<Channel>\d+)\s+ID:(?<ID>\d+)' -or
            $drvEvent.Line -match 'SMART-CH?[\s]+(?<Channel>\d+)\s+ID:(?<ID>\d+)') {
            $foundID = [int64]$Matches['ID']
            if ($foundID -eq $ScsiId) {
                if ($null -ne $Disk) {
                    $Disk.Failure = 2
                    $Disk.numOfBadSector = Get-MaxValue -Value1 $MaxBadSector -Value2 $BadSector
                    $Disk.FailureReason = Get-ErrorType -DrvEvent $drvEvent
                }
                return $drvEvent
            }
        }
    }
    return $null
}

$Global:TicketMapLookup = @{}

function Set-TicketMap {
    param($TicketMap, $QMS, $SerialNumber, $ReportTime, $FilePath)
    
    $key = "$QMS|$SerialNumber"
    if ($Global:TicketMapLookup.ContainsKey($key)) {
        return $null
    }
    
    $newTicket = [PSCustomObject]@{
        ModelName             = 0
        QMS                   = $QMS
        SN                    = $SerialNumber
        ReportTime            = $ReportTime
        LogLocation           = $FilePath
        MaxRespTime           = 0
        MaxTag                = 0
        MaxIOTimeout          = 0
        numOfFailDrv          = 0
        numOfFailDrvBeforeErr = 0
        numOfFailDrvAfterErr  = 0
        numOfFaidDrvNotFound  = 0
        numOfDrvNotFailed     = 0
        DiskList              = New-Object System.Collections.Generic.List[PSCustomObject]
    }
    
    $Global:TicketMapLookup[$key] = $newTicket
    $TicketMap.Add($newTicket)
    return $newTicket
}

function Update-TicketMap {
    param($TicketMap, $Conf)
    $TicketMap.ModelName = $Conf.Model
    $TicketMap.MaxRespTime = $Conf.MaxRespTime
    $TicketMap.MaxTag = $Conf.MaxTag
    $TicketMap.MaxIOTimeout = $Conf.MaxIOTimeout
}

function Search-TicketMap {
    param($TicketMap, $Ticket)
    
    $key = "$($Ticket.QMS)|$($Ticket.SN)"
    if ($Global:TicketMapLookup.ContainsKey($key)) {
        return -1
    }
    
    foreach ($item in $TicketMap) {
        if ($item.SN -eq $Ticket.SN -and
            $item.numOfFailDrv -eq $Ticket.numOfFailDrv -and
            $item.numOfFailDrvBeforeErr -eq $Ticket.numOfFailDrvBeforeErr -and
            $item.numOfFailDrvAfterErr -eq $Ticket.numOfFailDrvAfterErr -and
            $item.numOfFaidDrvNotFound -eq $Ticket.numOfFaidDrvNotFound -and
            $item.numOfDrvNotFailed -eq $Ticket.numOfDrvNotFailed) {
            return 1
        }
    }
    return 0
}

$Script:DiskMapCache = @{}

function Get-DiskMap {
    param($configPath)
    
    if ($Script:DiskMapCache.ContainsKey($configPath)) {
        return $Script:DiskMapCache[$configPath]
    }
    
    $configContent = Get-Content -Path $configPath -Raw
    $Model = $configContent -split 'Array'
    $ModelName = $Model[0]
    $regexResp = 'Maximum Drive Response Timeout:\s+(?<Value>\S+)'
    $respMatch = [regex]::Match($configContent, $regexResp)
    $maxRespTime = if ($respMatch.Success) { $respMatch.Groups['Value'].Value } else { "N/A" }
    $regexResp = 'Maximum Tag Count:\s+(?<Value>\S+)'
    $respMatch = [regex]::Match($configContent, $regexResp)
    $maxTag = if ($respMatch.Success) { $respMatch.Groups['Value'].Value } else { "8" }
    $regexResp = 'Disk I/O Timeout\(Sec\):\s+(?<Value>\S+)'
    $respMatch = [regex]::Match($configContent, $regexResp)
    $maxIOTimeOut = if ($respMatch.Success) { $respMatch.Groups['Value'].Value } else { "30" }

    $DiskList = New-Object System.Collections.Generic.List[PSCustomObject]
    $diskBlocks = $configContent -split '(?=#?Slot)'
    foreach ($block in $diskBlocks) {
        if ($block -match 'SCSI ID:\s+(?<ID>\d+)') {
            $id = $Matches['ID']
            $ldid = if ($block -match 'LD:\s+(?<LDID>[0-9A-Fa-f]+)') { $Matches['LDID'] } else { "N/A" }
            $vendor = if ($block -match 'Vender and Product ID:\s+(?<V>.*)') { $Matches['V'].Trim() } else { "N/A" }
            $rev = if ($block -match 'Revision Number:\s+(?<R>\S+)') { $Matches['R'] } else { "N/A" }
            $sn = if ($block -match 'Serial Number:\s+(?<S>\S+)') { $Matches['S'] } else { "N/A" }
            $cap = if ($block -match 'Disk Capacity \(blocks\):\s+(?<C>\d+)') { $Matches['C'] } else { 0 }

            $DiskList.Add([PSCustomObject]@{
                ID                   = [int]$id
                LDID                 = $ldid
                VendorProduct        = $vendor
                Revision             = $rev
                SerialNumber         = $sn
                SizeGB               = [Math]::Round([uint64]$cap * 512 / 1GB, 2)
                Failure              = 0
                FailureReason        = -1
                numOfBadSector       = 0
                IgnorenumOfBadSector = 0
            })
        }
    }
  
    $result = [PSCustomObject]@{
        Model        = $ModelName
        MaxRespTime  = $maxRespTime
        MaxTag       = $maxTag
        MaxIOTimeout = $maxIOTimeOut
        DiskList     = $DiskList | Sort-Object ID
    }
    
    $Script:DiskMapCache[$configPath] = $result
    return $result
}

function Get-DiskInMap {
    param($DisksList, $ScsiId)
    foreach ($disk in $DisksList) {
        if ($disk.ID -eq $ScsiId) {
            return $disk
        }
    }
    return $null
}

$Global:DiskModelLookup = @{}

function Set-DiskModel {
    param($DiskModelMap, $VendorProduct)
    $cols = $VendorProduct -split '\s+'
    $Vendor = $cols[0]
    $Model = $cols[1]
    $key = "$Vendor|$Model"
    
    if ($Global:DiskModelLookup.ContainsKey($key)) {
        $Global:DiskModelLookup[$key].Count++
        return $null
    }
    
    $NewDisk = [PSCustomObject]@{
        Vendor = $Vendor
        Model  = $Model
        Count  = 1
    }
    
    $DiskModelMap.Add($NewDisk)
    $Global:DiskModelLookup[$key] = $NewDisk
    return $NewDisk
}

function Get-OfficeID {
    param([string]$Path)
    if ($Path -match "[A-Za-z]+-\d+") {
        return $Matches[0]
    }
    return "XXX-Unknown"
}

function Test-DateTime-Before {
    param([DateTime]$Time1, [DateTime]$Time2)
    if ((($Time1 - $Time2).TotalMinutes) -gt 0) {
        return -1
    }
    return 1
}

function Set-DriveScan-Time {
    param($DriveScanList, $ScsiID, [DateTime]$Time)
    foreach ($Drv in $DriveScanList) {
        if ($Drv.ID -eq $ScsiID) {
            $Drv.ScanTime = $Time
            return $null
        }
    }
    $newDrv = [PSCustomObject]@{ID=$ScsiID; ScanTime=$Time}
    $DriveScanList.Add($newDrv)
    return $newDrv
}

function Set-LDRebuild-Time {
    param($RebuildList, $LD, $Starting, [DateTime]$Time)
    foreach ($rebuild in $RebuildList) {
        if ($rebuild.LDID -eq $LD) {
            if ($Starting -eq 1) {
                if ($null -eq $rebuild.EndTime) {
                    $rebuild.StartTime = $Time
                    return $null
                }
            }
            else {
                if ($null -eq $rebuild.EndTime -and $null -ne $rebuild.StartTime) {
                    $rebuild.EndTime = $Time
                    return $null
                }
            }
        }
    }
    if ($Starting -eq 0) { return $null }
    $newRebuild = [PSCustomObject]@{LDID=$LD; StartTime=$Time; EndTime=$null}
    $RebuildList.Add($newRebuild)
    return $newRebuild
}

function Trace-LDRebuiding {
    param($RebuildList, $LD, $Time)
    if ($null -eq $Time) { return 0 }
    foreach ($rebuild in $RebuildList) {
        if ($rebuild.LDID -eq $LD -and $null -ne $rebuild.EndTime -and $null -ne $rebuild.StartTime) {
            if (($rebuild.StartTime - $Time).TotalMinutes -le 0 -and ($Time - $rebuild.EndTime).TotalMinutes -le 0) {
                return 1
            }
        }
    }
    return 0
}

function Add-FailureDrv {
    param($DrvList, $ResultList, $Vendor)
    $ResultList.Add("")
    if ($Vendor) {
        $ResultList.Add("    $Vendor")
        $DrvList.Add($Vendor)
    }
}

function Get-DrvFailure-Reason {
    param($FailureEvent, $ScsiId)
    $reason = -1
    if ($FailureEvent -match 'M62: Chl (?<CHL>\d+) Id (?<ID>[0-9a-fA-F]+)') {    
        $foundID = [Convert]::ToInt64($Matches['ID'], 16)
        if ($foundID -eq $ScsiId) { $reason = 1 }
    }
    elseif ($FailureEvent -match 'Drive ChlNo:(?<CHL>\d+) ID:(?<ID>\d+)') {
        $foundID = [Convert]::ToInt64($Matches['ID'])
        if ($foundID -eq $ScsiId) { $reason = 2 }
    }
    elseif ($FailureEvent -match 'Drive Channel - Chl\((?<CHL>\d+)\) Id\((?<ID>\d+)\)') {
        $foundID = [Convert]::ToInt64($Matches['ID'])
        if ($foundID -eq $ScsiId) { $reason = 3 }
    }
    return $reason
}

