                if (Test-Path $configFilePath) { Copy-Item -Path $configfilePath -Destination (Join-Path $OutPutDir "${idPart}_config_${timestamp}.xml") -Force }
            }

            $MediaErrorSectReportOutput = Save-MediaErrorSect-Report -Report $finalReport -DiskMap $DiskMap -IssueTime $qmsIssueTime
            $debPath = Join-Path $fileInfo.DirectoryName "$idPart.deb.0.5.full.txt"
            $debList = [System.Collections.Generic.List[string]]::new()
