            $DrvFailBeforeTmout = -1; $DrvFailAfterTmoutReason = -1; $DrvFailBeforeErr = -1
            $numOfAnalysisDrv = 0; $lastTime = $null; $DoMore = 0
            $FailureDrvList = New-Object System.Collections.Generic.List[string]
