                            }
                            else { $errorlogList.Add("$($officeID): SCSI ID not found: $($ScsiId)."); $ScsiId = -1 }
                        }
                        $rebuilding = Trace-LDRebuiding -RebuildList $RebuildSeq -LD $LDID -Time $_.StartTime
                        if ($rebuilding -eq 0) {
                            if ($ScsiId -eq $_.DriveID) {
                                $currItem = $_
                                if ($DriveIsFailed -eq 0 -and [Math]::Abs(($_.StartTime - $lastTime).TotalDays) -gt $WeekThresholdDays) {
