                                            if ($sortingReport.Count -eq 1) { $lastTime = $item.StartTime }
                                        }
                                    }
                                    if ($MaxBadSector -lt $workingReport.Count) { $MaxBadSector = $workingReport.Count }
                                    $workingReport.Clear(); $sortingReport | ForEach-Object { $workingReport.Add($_.PSObject.Copy()) }
                                    Add-SectorToList -List $workingReport -DriveID $currItem.DriveID -GBZone $currItem.StartGB -Time $currItem.StartTime
                                    if ($workingReport.Count -eq 1) { $lastTime = $currItem.StartTime }
                                    $BadSector = $workingReport.Count
                                }
                                elseif ($DriveIsFailed -eq 0) {
                                    $sortingReport.Clear()
