                                        if ($currItem.StartGB -ne $item.StartGB) {
                                            $null = Add-SectorToList -List $sortingReport -DriveID $item.DriveID -GBZone $item.StartGB -Time $item.StartTime
                                            if ($sortingReport.Count -eq 1) { $lastTime = $item.StartTime }
                                        }
                                    }
                                    if ($MaxBadSector -lt $workingReport.Count) { $MaxBadSector = $workingReport.Count }
                                    $workingReport.Clear(); $sortingReport | ForEach-Object { $workingReport.Add($_.PSObject.Copy()) }
                                    if ($workingReport.Count -eq 1) { $lastTime = $currItem.StartTime }
                                    Add-SectorToList -List $workingReport -DriveID $currItem.DriveID -GBZone $currItem.StartGB -Time $currItem.StartTime
                                    $BadSector = $workingReport.Count
                                }
                                else {
                                    $dupSector = 0
                                    foreach ($item in $workingReport) {
                                        if ($currItem.StartGB -eq $item.StartGB) { $dupSector = 1; break }
                                    }
                                    if ($dupSector -eq 0) { Add-SectorToList -List $workingReport -DriveID $currItem.DriveID -GBZone $currItem.StartGB -Time $currItem.StartTime }
                                    $BadSector = $workingReport.Count
                                }
                            }
                        }
                        else { $CurrDisk.IgnorenumOfBadSector++ }
                        if ($BadSector -gt $MaxNumOfBadSectors -and $DriveIsFailed -eq 0) {
                            if ($numOfDrvFail -eq 0) { Write-Ticket-Title -LogList $analysisResultList -Qms $officeID -SerialNumber $idPart -StorageConf $StorageConfig }
                            $numOfDrvFail++; $numOfDrvFailCase++
                            $currentVendor = $DiskMap[$ScsiId.ToString()]
                            Add-FailureDrv -DrvList $FailureDrvList -ResultList $analysisResultList -Vendor $currentVendor
                            if ($null -ne $CurrDisk) {
                                $CurrDisk.numOfBadSector = Get-MaxValue -Value1 $MaxBadSector -Value2 $BadSector
                                $CurrDisk.Failure = 1
                                $DiskModel = Set-DiskModel -DiskModelMap $analysisDisks -VendorProduct $CurrDisk.VendorProduct
                                $thisTicket.DiskList.Add($CurrDisk)
                            }
                            else { $errorlogList.Add("$($officeID): SCSI ID not found: $($ScsiId).") }
                            $logList.Add("           $($_.StartTime | Get-Date -Format "yy-MM-dd HH-mm-ss") ID:$($ScsiId)     Drive Failure")
                            $analysisResultList.Add("           $($_.StartTime | Get-Date -Format "yy-MM-dd HH-mm-ss") ID:$($ScsiId)     Drive Failure")
                            $DriveIsFailed = 1; $DrvFailDetected = 1; $FailAlogDetected = 0; $DrvFailBeforeTmout = -1; $DrvFailAfterTmoutReason = -1; $DrvFailBeforeErr = -1
                            $EventTime = $_.StartTime; $reason = 0
                            $debList | ForEach-Object {
                                if ($DrvFailBeforeTmout -le 0) {
                                    $reason = Get-DrvFailure-Reason -FailureEvent $_ -ScsiId $ScsiId
                                    if ($reason -ge 0 -and $_ -match '(?<DateTime>\d{2}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2})') {
                                        $foundTime = [DateTime]::ParseExact($Matches['DateTime'], "yy-MM-dd HH:mm:ss", $null)
                                        if (($EventTime - $foundTime).TotalMinutes -le 0) {
                                            if ($DrvFailBeforeTmout -lt 0) { $DrvFailBeforeTmout = $reason }
                                            $FailAlogDetected = 1; $analysisResultList.Add($_); $logList.Add($_); return
                                        }
                                        else {
                                            $DrvFailBeforeTmout = 0
                                            if ($DrvFailAfterTmoutReason -lt 0) { $DrvFailAfterTmoutReason = $reason }
                                            $analysisResultList.Add($_); $logList.Add($_)
                                        }
                                    }
                                }
                            }
                            $FailAlogDetected = 0
                            $drvErrMatches | ForEach-Object {
                                if ($_.Line -match 'CH(?:L)?[:\s]+(?<Channel>\d+)\s+ID:(?<ID>\d+)' -or $_.Line -match 'SMART-CH?[\s]+(?<Channel>\d+)\s+ID:(?<ID>\d+)') {
                                    $foundID = [int64]$Matches['ID']
                                    if ($foundID -eq $ScsiId -and $FailAlogDetected -eq 0 -and $_.Line -match '(?<Date>\d{2}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})') {
                                        $foundTime = [DateTime]::ParseExact($Matches['Date'], "yy-MM-dd HH:mm:ss", $null)
                                        if (($EventTime - $foundTime).TotalMinutes -le 0) {
                                            if ($DrvFailBeforeErr -lt 0) { $DrvFailBeforeErr = 1 }
                                            $FailAlogDetected = 1; $analysisResultList.Add($_.Line); $logList.Add($_.Line); return
                                        }
                                        else {
                                            if ($_.Line -match $SmartErrorPattern -and $CurrDisk.FailureReason -le 0) { $CurrDisk.FailureReason = $SmartDetect }
                                            $DrvFailBeforeErr = 0; $analysisResultList.Add($_.Line); $logList.Add($_.Line)
                                        }
                                    }
                                }
                            }
                            if ($DrvFailBeforeErr -ge 0 -or $DrvFailBeforeTmout -ge 0) {
                                if ($DrvFailBeforeErr -eq 0 -or $DrvFailBeforeTmout -eq 0) {
                                    $numOfFailDrvAfterErr++; $numOfDrvFailAfterErrInThisQMS++
                                    if ($CurrDisk.FailureReason -le 0) { $CurrDisk.FailureReason = $DrvFailed + $DrvFailBeforeTmout }
                                }
                                else {
                                    $numOfFailDrvBeforeErr++; $numOfDrvFailBeforeErrInThisQMS++
                                    if ($CurrDisk.FailureReason -le 0) { $CurrDisk.FailureReason = $IOTimeout }
                                }
                            }
                        }
                    }
                }
            }

            if ($BadSector -le $MaxNumOfBadSectors -and $BadSector -gt $DefMinNumOfBadSector -and $DriveIsFailed -eq 0) {
                $CurrDisk = Get-DiskInMap -DisksList $StorageConfig.DiskList -ScsiId $ScsiId
                if ($null -ne $CurrDisk) {
                    $drvEvent = Get-Drive-Failure-Event -Disk $CurrDisk -ScsiId $ScsiId -drvErrLog $drvErrMatches
                    $thisTicket.DiskList.Add($CurrDisk)
                    if ($null -ne $drvEvent) {
                        if ($numOfDrvFail -eq 0) { Write-Ticket-Title -LogList $analysisResultList -Qms $officeID -SerialNumber $idPart -StorageConf $StorageConfig }
                        if ($CurrDisk.Failure -eq 2 -and $CurrDisk.FailureReason -eq -2) { $DoMore = 1 }
                        $numOfDrvFail++; $numOfDrvFailCase++; $numOfDrvFailButNotFound++
                        $currentVendor = $DiskMap[$ScsiId.ToString()]
                        Add-FailureDrv -DrvList $FailureDrvList -ResultList $analysisResultList -Vendor $currentVendor
                        $DiskModel = Set-DiskModel -DiskModelMap $analysisDisks -VendorProduct $CurrDisk.VendorProduct
                        $analysisResultList.Add($drvEvent.Line); $logList.Add($drvEvent.Line)
                    }
                    else { $CurrDisk.numOfBadSector = Get-MaxValue -Value1 $MaxBadSector -Value2 $BadSector; $numOfAnalysisDrv++ }
                }
                else { $errorlogList.Add("$($officeID): SCSI ID not found: $($ScsiId).") }
            }
            else {
                if ($null -ne $CurrDisk) { $CurrDisk.numOfBadSector = Get-MaxValue -Value1 $MaxBadSector -Value2 $BadSector }
                $DriveIsFailed = 0
            }
            if ($numOfDrvFail -gt 0) {
                $analysisResultList.Add("     number of the failure drives: $($numOfDrvFail)")
                $analysisResultList.Add("     number of before error : $($numOfDrvFailBeforeErrInThisQMS)")
                $analysisResultList.Add("     number of after error: $($numOfDrvFailAfterErrInThisQMS)")
                $analysisResultList.Add("     number of not found: $($numOfDrvFailButNotFound)")
                $NumOfNeedToCheck = $numOfDrvFail - ($numOfDrvFailBeforeErrInThisQMS + $numOfDrvFailAfterErrInThisQMS + $numOfDrvFailButNotFound)
                if ($NumOfNeedToCheck -gt 0) { $analysisResultList.Add("     number of need to check: $($NumOfNeedToCheck)") }
                $analysisResultList.Add("-----------------------------------------------------------------------------------")
                $analysisResultList.Add("")
                $thisTicket.numOfFailDrv = $numOfDrvFail
                $thisTicket.numOfFailDrvBeforeErr = $numOfDrvFailBeforeErrInThisQMS
                $thisTicket.numOfFailDrvAfterErr = $numOfDrvFailAfterErrInThisQMS
                $thisTicket.numOfFaidDrvNotFound = $numOfDrvFailButNotFound
                $thisTicket.numOfDrvNotFailed = $NumOfNeedToCheck
                $AllQMSTicketDB.Add($thisTicket)
                $logList.Add("[Success] $thisTicket.QMS \ $thisTicket.SN -> Ticket added")
            }
            elseif ($numOfAnalysisDrv -gt 0) { $AnalysisQMSTicketDB.Add($thisTicket) }

            $baseName = $fileInfo.BaseName
            $patternMatchOutPath = Join-Path $OutPutDir "${baseName}_${timestamp}_mediaerror.txt"
            $MediaErrorSectReportOutput | Out-File -FilePath $patternMatchOutPath -Encoding UTF8
            $sortedFinalReport | Select-Object DriveID, StartSector, GB_Zone, ErrorCount, StartTime, EndTime, Duration | Format-Table -AutoSize | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8
            $sortedFinalAnalysisReport | Select-Object DriveID, StartSector, GB_Zone, ErrorCount, StartTime, EndTime, Duration | Format-Table -AutoSize | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8
            $sortedDrvFailMatchResult.Line | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8

            $patternMatchOutPath = Join-Path $OutPutDir "${baseName}_${timestamp}_mediaerror_sorted.txt"
            $MediaErrorSectReportOutput | Out-File -FilePath $patternMatchOutPath -Encoding UTF8
            $sortedPatternMatchResult.Line | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8
            $StorageConfig.MaxRespTime | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8
            $StorageConfig.DiskList | Format-Table -AutoSize | Out-File -FilePath $patternMatchOutPath -Append -Encoding utf8
            
            $csvFilePath = Join-Path $OutPutDir "Disk_Error_Report_${baseName}_${timestamp}.csv"
            $sortedFinalReport | Select-Object DriveID, StartSector, GB_Zone, ErrorCount, StartTime, EndTime, Duration | Export-Csv -Path $csvFilePath -NoTypeInformation -Encoding UTF8

            if ($drvFailedMatches) {
                $evtList = [System.Collections.Generic.List[string]]::new()
                Get-Content $evtPath | ForEach-Object {
                    $cols = $_.Trim() -split '\s+'
                    if ($cols.Count -ge 7 -and $cols[6] -match $keywordPattern2) { $evtList.Add($_.Trim()) }
                }
                if ($evtList) {
                    $summary1List.Add("$($firstMatch.Path) : $($firstMatch.Line.Trim())")
                    $allMatches = $evtList + $debList
                    $sortedResults = $allMatches | Sort-Object { if ($_ -match '(?<DateTime>\d{2}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2})') { [DateTime]::ParseExact($Matches['DateTime'], "yy-MM-dd HH:mm:ss", $null) } else { [DateTime]::MinValue } }
                    $finalOutputPath = Join-Path $OutPutDir "${baseName}_${timestamp}_error.txt"
                    $MediaErrorSectReportOutput | Out-File -FilePath $finalOutputPath -Encoding UTF8
                    $sortedResults | Out-File -FilePath $finalOutputPath -Append -Encoding utf8
                    if ($BackupLogFile -eq 1) { Backup-Log-Files -FileInfo $fileInfo -SerialNumber $idPart -BaseName $baseName -TimeStamp $timestamp -OutPutDir $OutPutDir }
                    $logList.Add("[Success] $officeID \ $idPart -> File saved")
                }
            }
            else {
                $logList.Add("[Skip] File: $($evtPath) (Drive not failed yet)")
                if ($DrvFailDetected -eq 1) { $analysisResultList.Add("[Skip] File: $($evtPath) (Drive not failed yet)") }
                if ($BackupLogFile -eq 1) { Backup-Log-Files -FileInfo $fileInfo -SerialNumber $idPart -BaseName $baseName -TimeStamp $timestamp -OutPutDir $OutPutDir }
            }
            if ($DoMore -eq 1) { $processMorefileList.Add($evtPath) }
        }
        else {
            if ($matchCount -gt 0) { $logList.Add("[Skip] File: $($evtPath) (Only $matchCount records, below threshold)"); $unprocessfileList.Add($evtPath) }
            else { $unprocessfileList.Add($evtPath) }
        }
    }
}

if ($summaryList.Count -gt 0) {
    $summaryList | Out-File -FilePath $resultFile -Encoding utf8
    if ($summary1List.Count -gt 0) {
        $summary1List | Out-File -FilePath $resultFile1 -Encoding utf8
        Write-Host "`n[Done] Summary report saved to: $summaryFile1" -ForegroundColor Green
        Write-Host "[Done] Processed $($summary1List.Count) files containing errors." -ForegroundColor Green
    }
}
else { Write-Host "`nNo files matching the criteria were found." -ForegroundColor Yellow }

if ($logList.Count -gt 0) { $logList | Out-File -FilePath $logFile -Encoding utf8 }
if ($errorlogList.Count -gt 0) { $errorlogList | Out-File -FilePath $errrologFile -Encoding utf8 }

if ($analysisResultList.Count -gt 0) {
    $summaryList = New-Object System.Collections.Generic.List[string]
    $analysisResultList.Add("Total case: $($numOfDrvFailCase), Failed Drive before errors: $($numOfFailDrvBeforeErr), Failed Drive after errors: $($numOfFailDrvAfterErr)")
    $analysisFileTxt = $analysisFile + ".txt"
    $analysisResultList | Out-File -FilePath $analysisFileTxt -Encoding utf8
    $numOfQMS = $AllQMSTicketDB.Count
    $numOfDisk = 0; $numOfBefore = 0; $numOfAfter = 0; $numOfFaidDrvNotFound = 0; $numOfDrvNotFailed = 0
    $summaryList.Add("============================================================")
    $summaryList.Add("QMS        SN     numOfFailDrv numOfFailDrvBeforeErr numOfFailDrvAfterErr numOfFaidDrvNotFound     numOfDrvNotFailed")
    $summaryList.Add("---        --     ------------ --------------------- -------------------- --------------------")
    foreach ($ticket in $AllQMSTicketDB) {
        $dup = Search-TicketMap -TicketMap $AllQMSTicketDB -Ticket $ticket
        if ($dup -le 0) {
            $summaryList.Add("$($ticket.QMS) $($ticket.SN)        $($ticket.numOfFailDrv)               $($ticket.numOfFailDrvBeforeErr)                $($ticket.numOfFailDrvAfterErr)                           $($ticket.numOfFaidDrvNotFound)                 $($ticket.numOfDrvNotFailed)")
            $numOfDisk += $ticket.numOfFailDrv; $numOfBefore += $ticket.numOfFailDrvBeforeErr
            $numOfAfter += $ticket.numOfFailDrvAfterErr; $numOfFaidDrvNotFound += $ticket.numOfFaidDrvNotFound; $numOfDrvNotFailed += $ticket.numOfDrvNotFailed
        }
    }
    $summaryList.Add("---        --     ------------ --------------------- --------------------")
    $summaryList.Add("     $($numOfQMS)                    $($numOfDisk)               $($numOfBefore)                $($numOfAfter)                           $($numOfFaidDrvNotFound)                        $($numOfDrvNotFailed)")
    $summaryFileTxt = $summaryFile + ".txt"
    $summaryList | Out-File -FilePath $summaryFileTxt -Encoding utf8
    $summaryFileTxt = $summaryFile + "1.txt"
    $AllQMSTicketDB | Format-Table -AutoSize | Out-File -FilePath $summaryFileTxt -Encoding utf8
    if ($analysisDisks.Count -gt 0) { $analysisDisks | Format-Table -AutoSize | Out-File -FilePath $summaryFileTxt -Append -Encoding utf8 }
    Write-Ticket-Summary -cvsFilePath $summaryFile -QmsDB $AllQMSTicketDB
    Write-Ticket-Summary -cvsFilePath "$summaryFile`_unfailure" -QmsDB $AnalysisQMSTicketDB
    Write-Ticket-Summary-Readme
}

$unprocessfileList | Out-File -FilePath "unprocessedfile.txt" -Encoding utf8
$processfileList | Out-File -FilePath "processedfile.txt" -Encoding utf8
$processMorefileList | Out-File -FilePath "processmorefile.txt" -Encoding utf8

Write-Host "Total case: $($numOfDrvFailCase), Failed Drive before errors: $($numOfFailDrvBeforeErr), Failed Drive after errors: $($numOfFailDrvAfterErr), Drive Failure but not found: $($numOfFaidDrvNotFound), Drive analysis but not Fail: $($numOfDrvNotFailed)"
pause
